1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	export function nextGeneration(liveCells: Cell[]): Cell[] {
12	  const live = new Set(liveCells.map(cellKey));
13	  const tallies = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const [x, y] of liveCells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const cell: Cell = [x + dx, y + dy];
18	      const k = cellKey(cell);
19	      const existing = tallies.get(k);
20	      tallies.set(k, { cell, count: (existing?.count ?? 0) + 1 });
21	    }
22	  }
23	
24	  const survives = (k: string, count: number): boolean =>
25	    count === 3 || (count === 2 && live.has(k));
26	
27	  return [...tallies]
28	    .filter(([k, { count }]) => survives(k, count))
29	    .map(([, { cell }]) => cell);
30	}
