1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) unchanged (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(horizontal.sort());
24	  });
25	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
26	    // Center (1,1) has 4 live neighbors: (0,0),(1,0),(2,0),(0,1) -> dies
27	    const input: [number, number][] = [[0, 0], [1, 0], [2, 0], [0, 1], [1, 1]];
28	    const result = nextGeneration(input);
29	    expect(result).not.toContainEqual([1, 1]);
30	  });
31	  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
32	    // Dead cell (1,1) has 3 live neighbors: (0,0),(1,0),(0,1) -> becomes alive
33	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
34	    const result = nextGeneration(input);
35	    expect(result).toContainEqual([1, 1]);
36	  });
37	  it("should handle negative coordinates", () => {
38	    // Block at negative coordinates - should remain unchanged (still life)
39	    const block: [number, number][] = [[-1, -1], [0, -1], [-1, 0], [0, 0]];
40	    const result = nextGeneration(block);
41	    expect(result.sort()).toEqual(block.sort());
42	  });
43	});
