export function nextGeneration(liveCells: Cell[]): Cell[] {
  const live = new Set(liveCells.map(cellKey));
  const tallies = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const k = cellKey(cell);
      const existing = tallies.get(k);
      tallies.set(k, { cell, count: (existing?.count ?? 0) + 1 });
    }
  }

  const survives = (k: string, count: number): boolean =>
    count === 3 || (count === 2 && live.has(k));

  return [...tallies]
    .filter(([k, { count }]) => survives(k, count))
    .map(([, { cell }]) => cell);
}

