export function nextGeneration(liveCells: Cell[]): Cell[] {
  const live = new Set(liveCells.map(cellKey));
  const neighborsOf = ([x, y]: Cell): Cell[] =>
    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

  const candidates = new Map<string, Cell>();
  const counts = new Map<string, number>();
  for (const cell of liveCells.flatMap(neighborsOf)) {
    const k = cellKey(cell);
    candidates.set(k, cell);
    counts.set(k, (counts.get(k) ?? 0) + 1);
  }

  const survives = (k: string): boolean => {
    const n = counts.get(k) ?? 0;
    return n === 3 || (n === 2 && live.has(k));
  };

  return [...candidates].filter(([k]) => survives(k)).map(([, cell]) => cell);
}

